import React, { useEffect, useState } from "react";
import { io } from "socket.io-client";
import waveIcon from "../public/wave-icon.png";
import "./chatBot.css";

const socket = io("http://localhost:3002");

const ChatBot = () => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    socket.on("aiMessage", (msg) => {
      setMessages((prev) => [...prev, { type: "ai", text: msg }]);
    });

    return () => socket.off("aiMessage");
  }, []);

  const sendMessage = () => {
    if (!input.trim()) return;

    socket.emit("userMessage", input);
    setMessages((prev) => [...prev, { type: "user", text: input }]);
    setInput("");
  };

  return (
    <div className={`chat-container ${isOpen ? "open" : ""}`}>
      <button
        className="chat-header"
        onClick={() => setIsOpen(!isOpen)}
      >
        <img
          src={waveIcon}
          alt="Wave Agent"
          className="chat-icon"
        />
      </button>

      {isOpen && (
        <>
          <div className="chat-body">
            {messages.map((msg, i) => (
              <div key={i} className={`msg ${msg.type}`}>
                {msg.text}
              </div>
            ))}
          </div>

          <div className="chat-input">
            <input
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ask about portfolio or buy stock..."
            />
            <button onClick={sendMessage}>Send</button>
          </div>
        </>
      )}
    </div>
  );
};

export default ChatBot;
